    sources: [{ label: 'Service-Public — contenu, exclusions, prix et caractère facultatif de la garantie commerciale', href: 'https://www.service-public.fr/particuliers/vosdroits/F11093' }, { label: 'DGCCRF — clauses restrictives, main-d’œuvre, déplacement et pièces exclues', href: 'https://www.economie.gouv.fr/files/files/directions_services/dgccrf/documentation/publications/depliants/tout-savoir-sur-les-garanties.pdf' }, { label: 'Service-Public — garantie légale de conformité avant la couverture payante', href: 'https://www.service-public.fr/particuliers/vosdroits/F11094' }], lastVerified: '2026-07-19',
